content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kě yǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "可以幫我拿一個袋子嗎？謝謝。",
      "pinyin": "Kě yǐ bāng wǒ ná yī ge dài zi ma? Xiè xiè.",
      "pinyin_numeric": "ke3 yi3 bang1 wo3 na2 yi1 ge5 dai4 zi0 ma0? xie4 xie4.",
      "translation_en": "Can you help me get a bag? Thank you.",
      "translation_ko": "봉투 하나를 가져다 주시겠어요? 감사합니다."
    },
    {
      "text": "不好意思，可以給我菜單看一下嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ gěi wǒ cài dān kàn yī xià ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ke3 yi3 gei3 wo3 cai4 dan1 kan4 yi1 xia4 ma0?",
      "translation_en": "Excuse me, can you give me the menu to look at?",
      "translation_ko": "실례합니다, 메뉴를 좀 볼 수 있을까요?"
    },
    {
      "text": "我想要一杯紅茶，半糖少冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi hóng chá, bàn táng shǎo bīng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 hong2 cha2, ban4 tang2 shao3 bing1, ke3 yi3 ma0?",
      "translation_en": "I would like a black tea, half sugar and less ice, okay?",
      "translation_ko": "홍차 한 잔에 반당, 얼음 적게 해 주실 수 있나요?"
    },
    {
      "text": "請問，可以幫我加珍珠嗎？",
      "pinyin": "Qǐng wèn, kě yǐ bāng wǒ jiā zhēn zhū ma?",
      "pinyin_numeric": "qing3 wen4, ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0?",
      "translation_en": "Excuse me, can you add boba for me?",
      "translation_ko": "실례합니다, 타피오카 펄을 추가해 주시겠어요?"
    },
    {
      "text": "可以給我一根吸管嗎？麻煩你。",
      "pinyin": "Kě yǐ gěi wǒ yī gēn xī guǎn ma? Má fan nǐ.",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 yi1 gen1 xi1 guan3 ma0? ma2 fan5 ni3.",
      "translation_en": "Can you give me a straw? Please.",
      "translation_ko": "빨대 하나를 주시겠어요? 부탁드립니다."
    },
    {
      "text": "不好意思，可以再說一次嗎？我聽不太清楚。",
      "pinyin": "Bù hǎo yì si, kě yǐ zài shuō yī cì ma? Wǒ tīng bù tài qīng chǔ.",
      "pinyin_numeric": "bu4 hao3 yi4 si0, ke3 yi3 zai4 shuo1 yi1 ci4 ma0? wo3 ting1 bu4 tai4 qing1 chu3.",
      "translation_en": "Excuse me, can you say it again? I didn't hear clearly.",
      "translation_ko": "실례합니다, 한 번 더 말씀해 주시겠어요? 잘 안 들렸어요."
    },
    {
      "text": "可以請你幫我拍照嗎？謝謝。",
      "pinyin": "Kě yǐ qǐng nǐ bāng wǒ pāi zhào ma? Xiè xiè.",
      "pinyin_numeric": "ke3 yi3 qing3 ni3 bang1 wo3 pai1 zhao4 ma0? xie4 xie4.",
      "translation_en": "Can you please take a photo for me? Thank you.",
      "translation_ko": "사진을 찍어 주시겠어요? 감사합니다."
    },
    {
      "text": "我想要一杯豆漿，內用，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dòu jiāng, nèi yòng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 dou4 jiang1, nei4 yong4, ke3 yi3 ma0?",
      "translation_en": "I would like a cup of soy milk, for here, okay?",
      "translation_ko": "두유 한 잔을 매장에서 마시려고 하는데 괜찮을까요?"
    },
    {
      "text": "可以給我一個湯匙和衛生紙嗎？謝謝。",
      "pinyin": "Kě yǐ gěi wǒ yī ge tāng chí hé wèi shēng zhǐ ma? Xiè xiè.",
      "pinyin_numeric": "ke3 yi3 gei3 wo3 yi1 ge5 tang1 chi2 he2 wei4 sheng1 zhi3 ma0? xie4 xie4.",
      "translation_en": "Can you give me a spoon and a tissue? Thank you.",
      "translation_ko": "숟가락과 휴지를 주시겠어요? 감사합니다."
    }
  ]
}
